const items = $input.all();

const MAX_ITEMS = 8;
const MAX_AGE_HOURS = 120;
const cutoff = Date.now() - MAX_AGE_HOURS * 60 * 60 * 1000;

// Keep only high-value AI infra / model platform / measurable performance signals.
const strongKeywords = [
  'blackwell', 'hopper', 'gb200', 'b200', 'h200', 'h100', 'a100',
  'dgx', 'nvlink', 'grace', 'data center', 'datacenter', 'cluster',
  'nemo', 'nim', 'tensorrt', 'tensorrt-llm', 'triton', 'cuda', 'cudnn',
  'llm', 'lmm', 'inference', 'training', 'rag', 'agent', 'agents',
  'benchmark', 'throughput', 'latency', 'qps', 'tps', 'token/s',
  'cost reduction', 'production', 'ga', 'deployment', 'kubernetes', 'k8s'
];

// Hard-drop topics that are usually low signal for this intelligence workflow.
const hardBlockKeywords = [
  'geforce', 'rtx', 'dlss', 'ray tracing', 'raytracing',
  'gaming', 'game', 'unreal engine', 'unity',
  'graphics', 'rendering', 'creator', '3d art'
];

function toText(item) {
  const j = item.json || {};
  const cats = Array.isArray(j.categories) ? j.categories.join(' ') : '';
  return [j.title, j.contentSnippet, j.content, j.link, cats]
    .filter(Boolean)
    .join(' ')
    .toLowerCase();
}

function parseTs(item) {
  const j = item.json || {};
  const rawDate = j.isoDate || j.pubDate || j.date || j.published || null;
  const ts = rawDate ? Date.parse(rawDate) : NaN;
  return Number.isFinite(ts) ? ts : null;
}

function hasAny(text, keywords) {
  return keywords.some((k) => text.includes(k));
}

function scoreItem(item) {
  const j = item.json || {};
  const title = String(j.title || '').toLowerCase();
  const text = toText(item);

  if (!text) return -999;
  if (hasAny(text, hardBlockKeywords)) return -999;

  let score = 0;

  // Title hit is stronger than body hit.
  if (hasAny(title, strongKeywords)) score += 3;
  if (hasAny(text, strongKeywords)) score += 2;

  // Bonus for measurable signals.
  if (/(\d+\.?\d*\s*(%|x|ms|s|qps|tps|tokens\/s|token\/s))/i.test(text)) score += 1;
  if (/(benchmark|throughput|latency|cost|production|ga|deploy|deployment)/i.test(text)) score += 1;

  return score;
}

const kept = items
  .map((item) => {
    const ts = parseTs(item);
    const score = scoreItem(item);
    return { item, ts, score };
  })
  .filter((x) => x.score >= 3) // strict threshold: drop low-value content
  .filter((x) => x.ts === null || x.ts >= cutoff)
  .sort((a, b) => {
    if (b.score !== a.score) return b.score - a.score;
    return (b.ts || 0) - (a.ts || 0);
  })
  .slice(0, MAX_ITEMS)
  .map((x) => x.item);

return kept;

